+@code {
+    private const int MaxPhotos = 3;
+    private const long MaxPhotoSize = 5 * 1024 * 1024; // 5 MB
+
+    private ReviewModel _model = new();
+    private Dictionary<string, string> _serverErrors = new();
+    private List<PhotoInfo> _photoInfos = new();
+    private List<byte[]> _photoData = new();
+    private string? _photoError;
+    private bool _submitted;
+    private bool _isSubmitting;
+
+    private async Task OnPhotosSelected(InputFileChangeEventArgs e)
+    {
+        _photoError = null;
+        _photoInfos.Clear();
+        _photoData.Clear();
+
+        var files = e.GetMultipleFiles(MaxPhotos + 1);
+
+        if (files.Count > MaxPhotos)
+        {
+            _photoError = $"You can upload a maximum of {MaxPhotos} photos.";
+            return;
+        }
+
+        foreach (var file in files)
+        {
+            var extension = Path.GetExtension(file.Name).ToLowerInvariant();
+            if (extension is not ".jpg" and not ".jpeg" and not ".png")
+            {
+                _photoError = $"'{file.Name}' is not a supported format. Only JPG and PNG are allowed.";
+                _photoInfos.Clear();
+                _photoData.Clear();
+                return;
+            }
+
+            if (file.Size > MaxPhotoSize)
+            {
+                _photoError = $"'{file.Name}' exceeds the 5 MB size limit.";
+                _photoInfos.Clear();
+                _photoData.Clear();
+                return;
+            }
+
+            using var stream = file.OpenReadStream(maxAllowedSize: MaxPhotoSize);
+            using var ms = new MemoryStream();
+            await stream.CopyToAsync(ms);
+            _photoData.Add(ms.ToArray());
+            _photoInfos.Add(new PhotoInfo(file.Name, file.Size));
+        }
+    }
+
+    private async Task HandleSubmitAsync()
+    {
+        _serverErrors.Clear();
+        _isSubmitting = true;
+
+        try
+        {
+            var errors = await ReviewService.ValidateAndSubmitAsync(_model, _photoData);
+
+            if (errors.Count > 0)
+            {
+                _serverErrors = errors;
+            }
+            else
+            {
+                _submitted = true;
+            }
+        }
+        finally
+        {
+            _isSubmitting = false;
+        }
+    }
+
+    private static string FormatSize(long bytes)
+    {
+        return bytes switch
+        {
+            < 1024 => $"{bytes} B",
+            < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
+            _ => $"{bytes / (1024.0 * 1024.0):F2} MB"
+        };
+    }
+
+    private record PhotoInfo(string Name, long Size);
+}
